#!/usr/bin/env node
/**
 * Bundle framework files for webapp build
 * - Bundles Ruby files (lib/homura.rb + app/routes.rb) into src/ruby-bundle.ts
 * - Bundles CSS (app/styles.css) into src/styles-bundle.ts
 * - Copies JSX runtime from lib/jsx to src/lib
 */

import { readFileSync, writeFileSync, mkdirSync, copyFileSync, existsSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const webappRoot = join(__dirname, '..');
const frameworkRoot = join(__dirname, '../../..');

function escapeForTemplate(str) {
  return str
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$/g, '\\$');
}

function main() {
  // 1. Bundle Ruby files
  const homuraCore = readFileSync(join(frameworkRoot, 'lib/homura.rb'), 'utf-8');
  const userRoutes = readFileSync(join(webappRoot, 'app/routes.rb'), 'utf-8');

  const rubyBundle = `// Auto-generated by scripts/bundle-ruby.js
// DO NOT EDIT THIS FILE DIRECTLY - edit lib/homura.rb and app/routes.rb instead

export const HOMURA_CORE = \`${escapeForTemplate(homuraCore)}\`;

export const USER_ROUTES = \`${escapeForTemplate(userRoutes)}\`;
`;

  writeFileSync(join(webappRoot, 'src/ruby-bundle.ts'), rubyBundle);
  console.log('✅ Generated src/ruby-bundle.ts');

  // 2. Bundle CSS
  const cssPath = join(webappRoot, 'app/styles.css');
  if (existsSync(cssPath)) {
    const appCss = readFileSync(cssPath, 'utf-8');
    const cssBundle = `// Auto-generated by scripts/bundle-ruby.js
// DO NOT EDIT THIS FILE DIRECTLY - edit app/styles.css instead

export const APP_CSS = \`${escapeForTemplate(appCss)}\`;
`;
    writeFileSync(join(webappRoot, 'src/styles-bundle.ts'), cssBundle);
    console.log('✅ Generated src/styles-bundle.ts');
  }

  // 3. Copy JSX runtime from framework
  const libDir = join(webappRoot, 'src/lib');
  mkdirSync(libDir, { recursive: true });
  copyFileSync(
    join(frameworkRoot, 'lib/jsx/jsx-runtime.ts'),
    join(libDir, 'jsx-runtime.ts')
  );
  copyFileSync(
    join(frameworkRoot, 'lib/jsx/render.ts'),
    join(libDir, 'render.ts')
  );
  console.log('✅ Copied JSX runtime to src/lib/');
}

main();
